import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Sanitize user input to prevent XSS
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handling user input by encoding it before printing to a web page
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<head><title>XSS Secure</title></head>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");
        out.println(sanitizedInput);
        out.println("</body>");
        out.println("</html>");

        // Close the PrintWriter
        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
